import{_ as i,o as e,c as t,a2 as n}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/1727_中華化/20260430/F17_籌碼分佈與法人動態分析_投資研究員.md","filePath":"審計報告庫/財務審計/1727_中華化/20260430/F17_籌碼分佈與法人動態分析_投資研究員.md"}'),l={name:"審計報告庫/財務審計/1727_中華化/20260430/F17_籌碼分佈與法人動態分析_投資研究員.md"};function o(r,a,s,h,d,c){return e(),t("div",null,[...a[0]||(a[0]=[n('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的投資洞見。</p><h1 id="f17-籌碼分佈與法人動態分析-投資研究員-審計報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-投資研究員-審計報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>外資從2.2%回補至10%後，4/22-28淨賣超逾500萬張，派發紅燈已亮。千張大戶降至51.87%，集中放緩。投信短暫進場後撤退，缺乏第二買手。風險評級：中</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>外資從2.2%升至10.59%後回落至8.79%。千張大戶升至53.67%後回落至51.87%。中型戶從10,399降至9,056（-12.9%），籌碼超大手化但放緩。4月下旬外資四日淨賣超逾500萬張。投信短暫買超後撤退。股東人數從17,241降至15,557。外資獲利了結壓力未完全釋放。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="外資近期買賣超動向" tabindex="-1">外資近期買賣超動向 <a class="header-anchor" href="#外資近期買賣超動向" aria-label="Permalink to &quot;外資近期買賣超動向&quot;">​</a></h3><p>3-4 月外資高波動震盪：3/11-12 單日淨買超逾 260 萬張，4/22-28 轉為連續淨賣超逾 500 萬張。4/28 持股比率因增資稀釋（股本 125M→128M）從 8.19% 升至 8.75%，但持股數量實際減少，外資增資前已提前減碼。賣超與投信輕微買超形成方向性分歧，不具共識性合力。</p><h3 id="投信與千張大戶動向" tabindex="-1">投信與千張大戶動向 <a class="header-anchor" href="#投信與千張大戶動向" aria-label="Permalink to &quot;投信與千張大戶動向&quot;">​</a></h3><p>投信 2025 全年幾乎零交易，4/20-22 罕見連續買超後即轉賣超，鎖碼意願極低，4 月買超似事件驅動。千張大戶從 49.87% 升至 53.67% 後回落至 51.87%，高位獲利了結。中型戶從 10,399 降至 9,056（-12.9%），800-1000 張戶曾一度消失後回升至 3 戶，中大戶正在調整部位。散戶持股 &lt;1%，本檔風險主要來自法人行為。</p><h3 id="派發風險評估" tabindex="-1">派發風險評估 <a class="header-anchor" href="#派發風險評估" aria-label="Permalink to &quot;派發風險評估&quot;">​</a></h3><p>外資獲利了結壓力未完全釋放，若持續賣超，持股比率可能回落至 5-6% 區間。投信持股近乎零，無法提供買盤支撐，缺乏第二買手承接。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：外資 4 月下旬連續大額淨賣超（4/22-4/28 合計逾 500 萬張）已構成「派發紅燈」。外資從 2.2% 回補至 10% 徎的獲利了結壓力尚未完全釋放，若後續持續賣超，持股比率可能回落至 5-6% 區間，對股價形成實質壓力。投信持股比例極低（近乎零），無法提供買盤支撐，一旦外資持續撤退，將缺乏「第二買手」承接。</li><li><strong>空頭風險二</strong>：公司於 2026/04/28 增資（股本從 125,365,479 股增至 128,019,559 股，增幅 2.1%），在增資前外資已大幅減碼，代表「聰明錢」對增資後的稀釋效應已有預判。若增資用途（先進製程產線投資）的回報不如預期，將進一步壓縮評價空間。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK — TaiwanStockInstitutionalHolding（法人買賣超）取得 2025/01-2026/04 全部日數據；TaiwanStockForeignInvestorShareholding（外資持股）取得 2025/01-2026/04 全部日數據；TaiwanStockShareholdingSpread（股權分散表）取得 2025/01-2026/04 週數據</li><li><strong>yfinance</strong>: 不適用（本題以籌碼為主）</li><li><strong>年報/法說</strong>: 2024_Q4_1727_合併.pdf（年報資料庫）可用於質化補充，本報告未直接引用</li><li><strong>關鍵核對碼</strong>: <ul><li>外資持股比率 4/30: 8.79%（FinMind holding API）</li><li>千張大戶比例 4/17: 53.67%（FinMind backer_holding API）</li><li>4/22 外資淨賣超: -1,200,000 張（FinMind institutional API: buy 3,083,000, sell 4,283,000）</li><li>4/28 外資淨賣超: -1,401,000 張（FinMind institutional API: buy 4,831,200, sell 6,232,000）</li></ul></li></ul><hr><p><strong>資料來源</strong>：</p><ul><li>計算工具：FinMind 數據採集器.py（holding alias, institutional alias, backer_holding alias）</li><li>原始數據：FinMind TaiwanStockForeignInvestorShareholding, TaiwanStockInstitutionalHolding, TaiwanStockShareholdingSpread</li><li>查詢參數：stock_id=1727, start=2025-01-01, end=2026-05-01</li><li>網路搜尋：web_search（1727 中華化 借券賣出 餘額、1727 中華化 籌碼 法人 2026）</li></ul>',22)])])}const p=i(l,[["render",o]]);export{u as __pageData,p as default};
